package main

import (
	"fmt"
	"strings"
)

func main() {
	text := "Merhaba dunya bu bir test metni. Bu metin kelime sayma icin kullanilacak. Merhaba tekrar!"

	// Noktalama isaretlerini temizle
	cleanText := strings.NewReplacer(".", "", ",", "", "!", "").Replace(text)
	words := strings.Fields(strings.ToLower(cleanText))

	fmt.Println("Toplam kelime sayisi:", len(words))
	fmt.Println("Toplam karakter sayisi:", len(text))

	// Kelime frekansi
	wordCount := make(map[string]int)
	for _, word := range words {
		wordCount[word]++
	}

	fmt.Println("\nKelime frekanslari:")
	for word, count := range wordCount {
		fmt.Printf("'%s': %d kez\n", word, count)
	}

	// En uzun kelime
	longestWord := words[0]
	for _, word := range words {
		if len(word) > len(longestWord) {
			longestWord = word
		}
	}
	fmt.Printf("\nEn uzun kelime: '%s' (%d karakter)\n", longestWord, len(longestWord))

	// Ortalama kelime uzunlugu
	totalLength := 0
	for _, word := range words {
		totalLength += len(word)
	}
	avgLength := float64(totalLength) / float64(len(words))
	fmt.Printf("Ortalama kelime uzunlugu: %.2f\n", avgLength)
}
